ingredienti:[{nome:'Albumi',qt:'4'},{nome:'Zucchero semolato',qt:'200g'},{nome:'Panna fresca',qt:'300ml'},{nome:'Fragole fresche',qt:'400g'},{nome:'Zucchero a velo',qt:'20g'}],
